// ❌ BAD - no null check after FirstOrDefault causes NullReferenceException
var customer = db.Customers.FirstOrDefault(c => c.Email == email);
Console.WriteLine(customer.Name); // NRE if customer not found

// ✅ GOOD - check before use, or use First when absence is a bug
var customer = db.Customers.FirstOrDefault(c => c.Email == email);
if (customer is null)
    return Results.NotFound();

// Use First when a missing record is a program error
var settings = db.SystemSettings.First(s => s.Key == "PaymentGatewayUrl");
// throws if not found - correct, because missing settings is a bug

// ❌ BAD - exposing List<T> leaks implementation and allows callers to mutate
public List<OrderLine> GetLines(int orderId) => _repo.GetLines(orderId);
// caller can do: order.GetLines(1).Add(new OrderLine()); // mutates internal state

// ✅ GOOD - return least-specific read-only interface
public IReadOnlyList<OrderLine> GetLines(int orderId)
    => _repo.GetLines(orderId).AsReadOnly();

// IQueryable stays in database until materialized
public IQueryable<Order> GetPendingOrders()
    => _db.Orders.Where(o => o.Status == OrderStatus.Pending);
