// ❌ BAD - same usings repeated at the top of every file in the project
// OrderService.cs
using System.Collections.Generic;
using System.Linq;
using System.Threading.Tasks;
// CustomerService.cs - same block again
using System.Collections.Generic;
using System.Linq;

// ✅ GOOD - GlobalUsings.cs declares them once for the whole project
global using System.Collections.Generic;
global using System.Linq;
global using System.Threading.Tasks;
global using Microsoft.EntityFrameworkCore;
global using static System.Math;

// ❌ BAD - direct member access without null check
var customer = _db.Customers.FirstOrDefault(c => c.Id == id);
string city = customer.Address.City; // NRE if customer is null or Address is null

// ✅ GOOD - null-conditional chaining
var customer = _db.Customers.FirstOrDefault(c => c.Id == id);
string city = customer?.Address?.City ?? "Unknown";

// ✅ ALSO GOOD - explicit guard for early return
if (customer is null)
    return Results.NotFound($"Customer {id} not found");

string city = customer.Address?.City ?? "Unknown";

// ❌ BAD - null and empty handled incorrectly
string? email = GetEmail();
if (email == "") return; // misses null - NRE if email is null
if (email != null) SendConfirmation(email); // misses whitespace-only strings

// ✅ GOOD - use the right helper for the scenario
string? email = GetEmail();
if (string.IsNullOrWhiteSpace(email))
    return Results.BadRequest("Email is required");

// .NET 7+ parameter guard
void SendConfirmation(string email)
{
    ArgumentException.ThrowIfNullOrWhiteSpace(email);
    // proceed safely
}

// ❌ BAD - trying to inherit one enum from another - compile error
public enum BaseStatus { Active, Inactive }
// public enum ExtendedStatus : BaseStatus { Pending } // ERROR

// ✅ GOOD - specify underlying type only, add behavior via extension method
public enum OrderStatus : byte { Pending = 1, Processing = 2, Shipped = 3, Delivered = 4 }

public static class OrderStatusExtensions
{
    public static bool IsTerminal(this OrderStatus status)
        => status is OrderStatus.Shipped or OrderStatus.Delivered;

    public static string ToDisplayName(this OrderStatus status) => status switch
    {
        OrderStatus.Pending => "Awaiting processing",
        OrderStatus.Processing => "Being processed",
        _ => status.ToString()
    };
}

// ❌ BAD - verbose null checks that can be simplified
string displayName;
if (customer != null && customer.Name != null)
    displayName = customer.Name;
else
    displayName = "Guest";

// ✅ GOOD - null-conditional + null-coalescing in one expression
string displayName = customer?.Name ?? "Guest";

// ??= for lazy initialization
private List<Order>? _cache;
public List<Order> GetCached() {
    _cache ??= LoadFromDatabase();
    return _cache;
}

// Ternary for a non-null decision
decimal fee = order.Total > 1000m ? 0m : 9.99m;

// ❌ BAD - using dynamic when the type is known, losing all compile-time safety
dynamic paymentProcessor = GetProcessor();
paymentProcessor.Charge(order.Total); // no IDE help, errors at runtime

// ✅ GOOD - early binding with a known interface
IPaymentProcessor processor = GetProcessor();
processor.Charge(order.Total); // compile-time checked, IntelliSense, fast

